SELECT COUNT(*) AS total_contaminants
FROM contaminants
WHERE utility_id = 1;

SELECT name
FROM utilities
WHERE population_served > 100000;

SELECT staff_name, phone_number
FROM utility_staff
WHERE utility_id = 0;

SELECT name, population_served
FROM utilities
ORDER BY population_served DESC;

SELECT name
FROM utilities
WHERE utility_id = 0;

SELECT DISTINCT name
FROM utilities
WHERE utility_id IN (
  SELECT utility_id
  FROM violations
);

SELECT contaminant_name 
FROM contaminants 
WHERE sampling_point = 'Distribution System';

SELECT name
FROM utilities
WHERE utility_id IN (
  SELECT utility_id
  FROM contaminants
);
